import { icons } from 'lucide-react'

import { Icon } from '../../shared/dynamic-icon'

export interface Content12Props {
  title: string
  items: {
    title: string
    icon: string
  }[]
}

export function Content12({ title, items }: Readonly<Content12Props>) {
  return (
    <div className="grid w-full">
      <h2 className="mb-8 text-2xl font-bold">{title}</h2>
      <div className="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-3">
        {items.map((item, index) => (
          <div className="flex items-center gap-3" key={item.title + index}>
            <Icon
              name={item.icon as keyof typeof icons}
              className="text-primary size-4 flex-shrink-0"
            />
            <h3 className="text-base font-medium">{item.title}</h3>
          </div>
        ))}
      </div>
    </div>
  )
}

import { Content12, type Content12Props } from './content-12'

export const values = {
  title: 'Principles',
  items: [
    { title: 'Simple', icon: 'Zap' },
    { title: 'Clear', icon: 'Shield' },
    { title: 'Fast', icon: 'Code' },
    { title: 'Stable', icon: 'Users' },
    { title: 'Open', icon: 'Accessibility' },
    { title: 'Inclusive', icon: 'Smartphone' },
  ],
} satisfies Content12Props

export function Content12Example() {
  return <Content12 title={values.title} items={values.items} />
}
